-- ObjMapper bundle — PLAIN часть (метаданные + не-обфусцируемые модули)
script_name("Object Helper")
script_author("sexorcist")
script_version("1.0.1")

package.preload['objmapper.core.httpworker'] = function(...)
-- ════════════════════════════════════════════════════════════════════════
--  OP HTTP worker — ПЛЕЙН-модуль (НЕ обфусцируется!)
-- ════════════════════════════════════════════════════════════════════════
--  Эта функция исполняется в ОТДЕЛЬНОМ effil-OS-потоке. effil переносит её в
--  свежий Lua-state через string.dump, поэтому она ДОЛЖНА быть без upvalue'ов
--  (только globals + параметры). Любая обфускация (Vmify/EncryptStrings) добавит
--  upvalue'ы/глобальные зависимости и сломает перенос — поэтому модуль исключён
--  из Prometheus (build/bundle.py --plain). Секретов тут нет: обычный HTTP-запрос.
-- ════════════════════════════════════════════════════════════════════════
return function(method, url, auth, ct, cl, body, ver)
  local http  = require('socket.http')
  local ltn12 = require('ltn12')
  http.TIMEOUT = 5
  local hdrs = { ['Connection'] = 'close' }
  if auth then hdrs['Authorization']    = auth end
  if ct   then hdrs['Content-Type']     = ct   end
  if cl   then hdrs['Content-Length']   = cl   end
  if ver  then hdrs['X-Script-Version'] = ver  end
  local chunks = {}
  local ok_req, code = http.request({
    method  = method,
    url     = url,
    headers = hdrs,
    source  = body and ltn12.source.string(body) or nil,
    sink    = ltn12.sink.table(chunks),
  })
  return (ok_req ~= nil), (code or 0), table.concat(chunks)
end
end

